import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { ApiService } from './api.service';
import { PagedResult } from '../models/common.models';
import { UserListDto, UserDetailDto, CreateUserDto, UpdateUserDto, UserFilterDto } from '../models/user.models';

@Injectable({ providedIn: 'root' })
export class UserService {
  constructor(private api: ApiService) {}

  getAll(filter?: UserFilterDto): Observable<PagedResult<UserListDto>> {
    return this.api.getPaged<UserListDto>('users', filter as any);
  }

  getById(id: number): Observable<UserDetailDto> {
    return this.api.get<UserDetailDto>(`users/${id}`);
  }

  create(dto: CreateUserDto): Observable<UserDetailDto> {
    return this.api.post<UserDetailDto>('users', dto);
  }

  update(id: number, dto: UpdateUserDto): Observable<UserDetailDto> {
    return this.api.put<UserDetailDto>(`users/${id}`, dto);
  }

  delete(id: number): Observable<void> {
    return this.api.delete(`users/${id}`);
  }

  resendInvitation(id: number): Observable<void> {
    return this.api.post<void>(`users/${id}/resend-invitation`, {});
  }
}
